sql:
SELECT AVG(file_size) AS average_file_size
FROM image_files
WHERE uploader_id = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT COUNT(DISTINCT file_id) 
FROM file_environments 
WHERE compatible = 1;

SELECT COUNT(DISTINCT fe.file_id) AS total_compatible_files
FROM file_environments AS fe
WHERE fe.compatible = 1;

